// Fasig-Tipton "The July Sale" 2026 — expert pedigree intelligence.
//
// A hand-analyzed pedigree read for every hip in the FT July 2026 catalog, used
// as the AUTHORITATIVE pedigree grade for these hips (see pedigreeGrade.ts): the
// catalog-page black-type heuristic is a proxy, but this dataset scores signals
// the page text can't expose — first-dam production, juvenile evidence, sire-line
// reliability, and confidence in a young sire's projection. Where a hip is
// covered here, this grade wins; otherwise the heuristic applies.
//
// Source: Fasig-Tipton July 2026 Pedigree Intelligence
//   (https://www.fasigtipton.com/catalogs/2026/0714/web.pdf)
// Scale: A/A- strongest - B+ meaningful positive - B/B- useful with limits -
//   C range more speculative. Score is 0-100 (catalog-pedigree only).
// Not included: conformation, vet findings, biomechanics, temperament, sale
//   price — these must be layered on before purchase.
//
// Generated from the source spreadsheet; edit there and regenerate rather than
// hand-editing rows.

import { normalizeEntityName } from '@furlong/shared';

/** The sale this dataset describes. Matched loosely on name (contains "july"). */
export const FT_JULY_2026 = {
  auctionHouse: 'FASIG_TIPTON',
  year: 2026,
  nameIncludes: 'july',
} as const;

export type ExpertGrade = 'A+' | 'A' | 'A-' | 'B+' | 'B' | 'B-' | 'C+' | 'C' | 'C-' | 'D' | 'F';
export type ExpertConfidence = 'High' | 'Medium' | 'Low';

export interface ExpertPedigree {
  hip: number;
  /** Sire on the source page — cross-checked against the DB so a renumbered
   *  catalog can't misattribute a grade. Null where the source page omitted it. */
  sire: string | null;
  score: number; // 0-100
  grade: ExpertGrade;
  confidence: ExpertConfidence;
  surface: string;
  distance: string;
  maturity: string;
  positives: string;
  risks: string;
  hiddenAngle: string;
}

