// hip -> record, for O(1) lookup.
const BY_HIP = new Map<number, ExpertPedigree>(FT_JULY_2026_PEDIGREE.map((e) => [e.hip, e]));

/** True when a sale is the FT July 2026 yearling sale this dataset covers. */
export function isFtJuly2026(sale: {
  auctionHouse: string;
  name: string;
  year: number;
}): boolean {
  return (
    sale.auctionHouse === FT_JULY_2026.auctionHouse &&
    sale.year === FT_JULY_2026.year &&
    sale.name.toLowerCase().includes(FT_JULY_2026.nameIncludes)
  );
}

/**
 * Expert record for a hip, or null. Requires the sire to match (normalized) so a
 * catalog that was renumbered after this dataset was built can't hand a hip the
 * wrong grade — on a mismatch we return null and the caller falls back to the
 * black-type heuristic.
 */
export function expertPedigreeFor(args: {
  auctionHouse: string;
  saleName: string;
  year: number;
  hipNumber: number;
  sireName: string | null;
}): ExpertPedigree | null {
  if (!isFtJuly2026({ auctionHouse: args.auctionHouse, name: args.saleName, year: args.year })) {
    return null;
  }
  const rec = BY_HIP.get(args.hipNumber);
  if (!rec) return null;
  const want = normalizeEntityName(rec.sire);
  const got = normalizeEntityName(args.sireName);
  if (want && got && want !== got) return null;
  return rec;
}
